export type FileManagerFileStatus = "available" | "conflict" | "error" | "offline" | "syncing";
export type FileManagerUploadStatus =
  "cancelled" | "complete" | "error" | "paused" | "queued" | "retrying" | "uploading";

export interface FileManagerFolder {
  /** Optional immutable child folders used to build hierarchical navigation. */
  readonly children?: readonly FileManagerFolder[];
  /** Stable unique folder identifier used for navigation and move destinations. */
  readonly id: string;
  /** Human-readable folder name shown in the navigation tree. */
  readonly label: string;
}

export interface FileManagerFile {
  /** Identifier of the folder currently containing this file. */
  readonly folderId: string;
  /** Stable unique file identifier used for selection and adapter operations. */
  readonly id: string;
  /** Consumer-reported MIME type shown as metadata and preview context. */
  readonly mimeType: string;
  /** ISO-compatible modification instant used for localized metadata display. */
  readonly modifiedAt: string;
  /** Human-readable file name used for display and rename editing. */
  readonly name: string;
  /** Optional authorization level controlling whether file mutations are available. */
  readonly permission?: "manage" | "read-only";
  /** Non-negative file size in bytes used for localized metadata display. */
  readonly size: number;
  /** Optional synchronization lifecycle used for status and conflict context. */
  readonly status?: FileManagerFileStatus;
}

export interface FileManagerUpload {
  /** Optional recovery message for an errored upload. */
  readonly error?: string;
  /** Stable unique upload identifier used for retry and cancellation operations. */
  readonly id: string;
  /** Human-readable upload file name. */
  readonly name: string;
  /** Optional percentage from zero through 100 for progress presentation. */
  readonly progress?: number;
  /** Current upload lifecycle controlling progress and available actions. */
  readonly status: FileManagerUploadStatus;
  /** Total upload byte count paired with `uploadedBytes`. */
  readonly totalBytes: number;
  /** Completed upload byte count paired with `totalBytes`. */
  readonly uploadedBytes: number;
}

export interface FileManagerConflict {
  /** Identifier of the file requiring conflict resolution. */
  readonly fileId: string;
  /** Stable unique conflict identifier passed to adapter resolution. */
  readonly id: string;
  /** Human-readable description of the local version. */
  readonly localDescription: string;
  /** Human-readable description of the remote version. */
  readonly remoteDescription: string;
  /** Concise conflict explanation shown before resolution actions. */
  readonly summary: string;
}

export interface FileManagerStorage {
  /** Total storage capacity in bytes. */
  readonly totalBytes: number;
  /** Used storage capacity in bytes. */
  readonly usedBytes: number;
}

export interface FileManagerSnapshot {
  /** Immutable unresolved conflict records supplied by the adapter. */
  readonly conflicts: readonly FileManagerConflict[];
  /** Immutable file records available to the current workspace. */
  readonly files: readonly FileManagerFile[];
  /** Immutable hierarchical folders used for navigation and move destinations. */
  readonly folders: readonly FileManagerFolder[];
  /** Optional storage capacity context; omission removes the storage summary. */
  readonly storage?: FileManagerStorage;
  /** Immutable upload records used for progress and recovery actions. */
  readonly uploads: readonly FileManagerUpload[];
}

export interface FileManagerRecoveryReceipt {
  /** Removed file record retained for the bounded recovery action. */
  readonly file: FileManagerFile;
  /** Opaque consumer-owned token required to restore the removed file. */
  readonly token: string;
}

export type FileManagerConflictResolution = "keep-local" | "keep-remote";

export interface FileManagerAdapter {
  /** Optionally cancels one upload; omission cleanly removes cancellation actions. */
  readonly cancelUpload?: (uploadId: string, signal: AbortSignal) => Promise<FileManagerUpload>;
  /** Loads the latest immutable file workspace snapshot. */
  readonly load: (signal: AbortSignal) => Promise<FileManagerSnapshot>;
  /** Moves one manageable file and returns its canonical updated record. */
  readonly move: (
    fileId: string,
    folderId: string,
    signal: AbortSignal,
  ) => Promise<FileManagerFile>;
  /** Removes a file into consumer-owned recovery and returns its opaque receipt. */
  readonly moveToRecovery: (
    fileId: string,
    signal: AbortSignal,
  ) => Promise<FileManagerRecoveryReceipt>;
  /** Renames one manageable file and returns its canonical updated record. */
  readonly rename: (
    fileId: string,
    nextName: string,
    signal: AbortSignal,
  ) => Promise<FileManagerFile>;
  /** Optionally resolves one conflict; omission cleanly removes resolution actions. */
  readonly resolveConflict?: (
    conflictId: string,
    resolution: FileManagerConflictResolution,
    signal: AbortSignal,
  ) => Promise<FileManagerFile>;
  /** Restores a removed file using an opaque consumer-issued recovery token. */
  readonly restore: (token: string, signal: AbortSignal) => Promise<FileManagerFile>;
  /** Optionally retries one upload; omission cleanly removes retry actions. */
  readonly retryUpload?: (uploadId: string, signal: AbortSignal) => Promise<FileManagerUpload>;
}

const FIXTURE_EPOCH_TIME = "1970-01-01T00:00:00.000Z";

export function createDeterministicFileManagerSnapshot(): FileManagerSnapshot {
  return {
    conflicts: [
      {
        fileId: "release-notes",
        id: "release-notes-conflict",
        localDescription: "Edited locally at 10:28 UTC",
        remoteDescription: "Updated remotely at 10:29 UTC",
        summary: "Two versions of Release notes.txt need a decision.",
      },
    ],
    files: [
      {
        folderId: "working-set",
        id: "interface-map",
        mimeType: "application/pdf",
        modifiedAt: FIXTURE_EPOCH_TIME,
        name: "Interface map.pdf",
        permission: "manage",
        size: 2_420_736,
        status: "available",
      },
      {
        folderId: "working-set",
        id: "release-notes",
        mimeType: "text/plain",
        modifiedAt: FIXTURE_EPOCH_TIME,
        name: "Release notes.txt",
        permission: "manage",
        size: 18_432,
        status: "conflict",
      },
      {
        folderId: "reference",
        id: "token-reference",
        mimeType: "application/json",
        modifiedAt: FIXTURE_EPOCH_TIME,
        name: "Token reference.json",
        permission: "read-only",
        size: 82_944,
        status: "available",
      },
    ],
    folders: [
      {
        children: [
          { id: "working-set", label: "Working set" },
          { id: "reference", label: "Reference" },
        ],
        id: "workspace",
        label: "Workspace",
      },
    ],
    storage: { totalBytes: 10_737_418_240, usedBytes: 4_563_402_752 },
    uploads: [
      {
        id: "upload-accessibility-notes",
        name: "Accessibility notes.pdf",
        progress: 64,
        status: "uploading",
        totalBytes: 1_048_576,
        uploadedBytes: 671_089,
      },
    ],
  };
}

function ensureActive(signal: AbortSignal): void {
  if (signal.aborted) throw new DOMException("The operation was aborted.", "AbortError");
}

function requireFile(snapshot: FileManagerSnapshot, id: string): FileManagerFile {
  const file = snapshot.files.find((candidate) => candidate.id === id);
  if (file === undefined) throw new Error("The requested file is no longer available.");
  return file;
}

function replaceFile(
  snapshot: FileManagerSnapshot,
  replacement: FileManagerFile,
): FileManagerSnapshot {
  return {
    ...snapshot,
    files: snapshot.files.map((file) => (file.id === replacement.id ? replacement : file)),
  };
}

export function createDeterministicFileManagerAdapter(): FileManagerAdapter {
  let snapshot = createDeterministicFileManagerSnapshot();
  const recovery = new Map<string, FileManagerFile>();
  return {
    async cancelUpload(uploadId, signal) {
      ensureActive(signal);
      const current = snapshot.uploads.find((upload) => upload.id === uploadId);
      if (current === undefined) throw new Error("The upload is no longer available.");
      const next: FileManagerUpload = { ...current, status: "cancelled" };
      snapshot = {
        ...snapshot,
        uploads: snapshot.uploads.map((upload) => (upload.id === uploadId ? next : upload)),
      };
      return next;
    },
    async load(signal) {
      ensureActive(signal);
      return snapshot;
    },
    async move(fileId, folderId, signal) {
      ensureActive(signal);
      const next = {
        ...requireFile(snapshot, fileId),
        folderId,
        modifiedAt: FIXTURE_EPOCH_TIME,
      };
      snapshot = replaceFile(snapshot, next);
      return next;
    },
    async moveToRecovery(fileId, signal) {
      ensureActive(signal);
      const file = requireFile(snapshot, fileId);
      const token = `recovery-${file.id}`;
      recovery.set(token, file);
      snapshot = {
        ...snapshot,
        files: snapshot.files.filter((candidate) => candidate.id !== fileId),
      };
      return { file, token };
    },
    async rename(fileId, nextName, signal) {
      ensureActive(signal);
      const normalized = nextName.trim();
      if (normalized.length === 0 || normalized.length > 255 || /[\\/:*?"<>|]/u.test(normalized)) {
        throw new Error("Use a file name from 1 to 255 characters without reserved symbols.");
      }
      const next = {
        ...requireFile(snapshot, fileId),
        modifiedAt: FIXTURE_EPOCH_TIME,
        name: normalized,
      };
      snapshot = replaceFile(snapshot, next);
      return next;
    },
    async resolveConflict(conflictId, resolution, signal) {
      ensureActive(signal);
      const conflict = snapshot.conflicts.find((candidate) => candidate.id === conflictId);
      if (conflict === undefined) throw new Error("The conflict is no longer available.");
      const current = requireFile(snapshot, conflict.fileId);
      const next = {
        ...current,
        modifiedAt: FIXTURE_EPOCH_TIME,
        name: resolution === "keep-local" ? current.name : current.name,
        status: "available" as const,
      };
      snapshot = {
        ...replaceFile(snapshot, next),
        conflicts: snapshot.conflicts.filter((candidate) => candidate.id !== conflictId),
      };
      return next;
    },
    async restore(token, signal) {
      ensureActive(signal);
      const file = recovery.get(token);
      if (file === undefined) throw new Error("The recovery window has expired.");
      recovery.delete(token);
      snapshot = { ...snapshot, files: [...snapshot.files, file] };
      return file;
    },
    async retryUpload(uploadId, signal) {
      ensureActive(signal);
      const current = snapshot.uploads.find((upload) => upload.id === uploadId);
      if (current === undefined) throw new Error("The upload is no longer available.");
      const { error: _error, ...uploadWithoutError } = current;
      const next: FileManagerUpload = { ...uploadWithoutError, status: "retrying" };
      snapshot = {
        ...snapshot,
        uploads: snapshot.uploads.map((upload) => (upload.id === uploadId ? next : upload)),
      };
      return next;
    },
  };
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

import type {
  FileManagerAdapter,
  FileManagerConflictResolution,
  FileManagerFile,
  FileManagerRecoveryReceipt,
  FileManagerSnapshot,
  FileManagerUpload,
} from "./file-manager-adapter";

export type FileManagerLoadState = "empty" | "error" | "loading" | "offline" | "ready";
export type FileManagerOperationState = "error" | "idle" | "pending" | "success";

export interface UseFileManagerOptions {
  /** Consumer adapter that owns file data, authorization, mutations, and recovery. */
  readonly adapter: FileManagerAdapter;
  /** Optional server-provided snapshot that bypasses the initial adapter load. */
  readonly initialSnapshot?: FileManagerSnapshot;
  /** Prevents adapter requests and exposes explicit offline recovery state. */
  readonly offline?: boolean;
}

function replaceFile(snapshot: FileManagerSnapshot, file: FileManagerFile): FileManagerSnapshot {
  return {
    ...snapshot,
    files: snapshot.files.map((candidate) => (candidate.id === file.id ? file : candidate)),
  };
}

function replaceUpload(
  snapshot: FileManagerSnapshot,
  upload: FileManagerUpload,
): FileManagerSnapshot {
  return {
    ...snapshot,
    uploads: snapshot.uploads.map((candidate) => (candidate.id === upload.id ? upload : candidate)),
  };
}

export function useFileManager({
  adapter,
  initialSnapshot,
  offline = false,
}: UseFileManagerOptions) {
  const [snapshot, setSnapshot] = useState<FileManagerSnapshot | null>(initialSnapshot ?? null);
  const [state, setState] = useState<FileManagerLoadState>(
    offline
      ? "offline"
      : initialSnapshot === undefined
        ? "loading"
        : initialSnapshot.files.length === 0
          ? "empty"
          : "ready",
  );
  const [error, setError] = useState("");
  const [operationState, setOperationState] = useState<FileManagerOperationState>("idle");
  const [operationError, setOperationError] = useState("");
  const [lastRecovery, setLastRecovery] = useState<FileManagerRecoveryReceipt | null>(null);
  const activeRequest = useRef<AbortController | null>(null);

  const reload = useCallback(async () => {
    if (offline) {
      setState("offline");
      return;
    }
    activeRequest.current?.abort();
    const controller = new AbortController();
    activeRequest.current = controller;
    setState("loading");
    setError("");
    try {
      const next = await adapter.load(controller.signal);
      if (controller.signal.aborted) return;
      setSnapshot(next);
      setState(next.files.length === 0 ? "empty" : "ready");
    } catch (loadError) {
      if (controller.signal.aborted) return;
      setError(
        loadError instanceof Error ? loadError.message : "The file workspace could not load.",
      );
      setState("error");
    }
  }, [adapter, offline]);

  useEffect(() => {
    if (initialSnapshot === undefined) void reload();
    return () => activeRequest.current?.abort();
  }, [initialSnapshot, reload]);

  const operate = async <T>(
    action: (signal: AbortSignal) => Promise<T>,
    apply: (current: FileManagerSnapshot, result: T) => FileManagerSnapshot,
  ): Promise<T | null> => {
    if (offline || snapshot === null) return null;
    activeRequest.current?.abort();
    const controller = new AbortController();
    activeRequest.current = controller;
    setOperationState("pending");
    setOperationError("");
    try {
      const result = await action(controller.signal);
      if (controller.signal.aborted) return null;
      setSnapshot((current) => (current === null ? current : apply(current, result)));
      setOperationState("success");
      return result;
    } catch (operationFailure) {
      if (controller.signal.aborted) return null;
      setOperationError(
        operationFailure instanceof Error
          ? operationFailure.message
          : "The file operation could not be completed.",
      );
      setOperationState("error");
      return null;
    }
  };

  const rename = (fileId: string, nextName: string) =>
    operate(
      (signal) => adapter.rename(fileId, nextName, signal),
      (current, file) => replaceFile(current, file),
    );
  const move = (fileId: string, folderId: string) =>
    operate(
      (signal) => adapter.move(fileId, folderId, signal),
      (current, file) => replaceFile(current, file),
    );
  const moveToRecovery = async (fileId: string) => {
    const receipt = await operate(
      (signal) => adapter.moveToRecovery(fileId, signal),
      (current, result) => ({
        ...current,
        files: current.files.filter((file) => file.id !== result.file.id),
      }),
    );
    if (receipt !== null) setLastRecovery(receipt);
    return receipt;
  };
  const restore = async () => {
    if (lastRecovery === null) return null;
    const file = await operate(
      (signal) => adapter.restore(lastRecovery.token, signal),
      (current, restored) => ({ ...current, files: [...current.files, restored] }),
    );
    if (file !== null) setLastRecovery(null);
    return file;
  };
  const resolveConflict = (conflictId: string, resolution: FileManagerConflictResolution) => {
    if (adapter.resolveConflict === undefined) return Promise.resolve(null);
    return operate(
      (signal) => adapter.resolveConflict!(conflictId, resolution, signal),
      (current, file) => ({
        ...replaceFile(current, file),
        conflicts: current.conflicts.filter((conflict) => conflict.id !== conflictId),
      }),
    );
  };
  const cancelUpload = (uploadId: string) => {
    if (adapter.cancelUpload === undefined) return Promise.resolve(null);
    return operate(
      (signal) => adapter.cancelUpload!(uploadId, signal),
      (current, upload) => replaceUpload(current, upload),
    );
  };
  const retryUpload = (uploadId: string) => {
    if (adapter.retryUpload === undefined) return Promise.resolve(null);
    return operate(
      (signal) => adapter.retryUpload!(uploadId, signal),
      (current, upload) => replaceUpload(current, upload),
    );
  };

  return {
    cancelUpload,
    error,
    lastRecovery,
    move,
    moveToRecovery,
    operationError,
    operationState,
    reload,
    rename,
    resolveConflict,
    restore,
    retryUpload,
    snapshot,
    state,
  } as const;
}

@layer mergora.components {
  .mrg-file-manager {
    display: grid;
    grid-template-columns: minmax(13rem, 18rem) minmax(0, 1fr);
    max-inline-size: var(--mrg-semantic-size-content-wide);
    overflow: clip;
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-strong);
    border-radius: var(--mrg-semantic-radius-panel);
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-canvas);
    font-family: var(--mrg-semantic-font-family-prose);
  }

  .mrg-file-manager h1,
  .mrg-file-manager h2,
  .mrg-file-manager h3,
  .mrg-file-manager p {
    margin-block: 0;
  }

  .mrg-file-manager h1 {
    font-size: var(--mrg-semantic-font-size-heading-medium);
    line-height: var(--mrg-semantic-font-line-height-heading);
    text-wrap: balance;
  }

  .mrg-file-manager h2 {
    font-size: var(--mrg-semantic-font-size-heading-small);
    line-height: var(--mrg-semantic-font-line-height-heading);
  }

  .mrg-file-manager [data-slot="file-manager-header"] {
    grid-column: 1 / -1;
    display: flex;
    align-items: start;
    justify-content: space-between;
    gap: var(--mrg-semantic-space-stack-md);
    padding: var(--mrg-semantic-density-panel-padding);
    border-block-end: var(--mrg-semantic-border-width-emphasis) solid
      var(--mrg-semantic-color-brand-action);
  }

  .mrg-file-manager [data-slot="file-manager-header"] p,
  .mrg-file-manager [data-slot="file-manager-section-heading"] p,
  .mrg-file-manager [data-slot="file-manager-file-copy"] span {
    color: var(--mrg-semantic-color-foreground-muted);
    font-size: var(--mrg-semantic-font-size-caption);
  }

  .mrg-file-manager [data-slot="file-manager-view"],
  .mrg-file-manager [data-slot="file-manager-actions"] {
    display: flex;
    flex-wrap: wrap;
    gap: var(--mrg-semantic-space-inline-xs);
  }

  .mrg-file-manager [data-slot="file-manager-folders"] {
    min-inline-size: 0;
    padding: var(--mrg-semantic-density-panel-padding);
    border-inline-end: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-default);
    background: var(--mrg-semantic-color-background-surface);
  }

  .mrg-file-manager [data-slot="file-manager-folders"] h2 {
    margin-block-end: var(--mrg-semantic-space-stack-sm);
  }

  .mrg-file-manager [data-slot="file-manager-content"] {
    display: grid;
    align-content: start;
    grid-template-columns: minmax(0, 1fr) minmax(15rem, 0.45fr);
    gap: 0;
    min-inline-size: 0;
  }

  .mrg-file-manager [data-slot="file-manager-files"],
  .mrg-file-manager [data-slot="file-manager-preview"],
  .mrg-file-manager [data-slot="file-manager-uploads"],
  .mrg-file-manager [data-slot="file-manager-conflicts"],
  .mrg-file-manager [data-slot="file-manager-storage"] {
    min-inline-size: 0;
    padding: var(--mrg-semantic-density-panel-padding);
    border-block-end: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-default);
  }

  .mrg-file-manager [data-slot="file-manager-preview"] {
    border-inline-start: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-default);
    background: var(--mrg-semantic-color-background-surface);
  }

  .mrg-file-manager [data-slot="file-manager-uploads"],
  .mrg-file-manager [data-slot="file-manager-conflicts"] {
    grid-column: 1 / -1;
  }

  .mrg-file-manager [data-slot="file-manager-section-heading"] {
    display: flex;
    align-items: start;
    justify-content: space-between;
    gap: var(--mrg-semantic-space-inline-sm);
    margin-block-end: var(--mrg-semantic-space-stack-md);
  }

  .mrg-file-manager [data-slot="file-manager-file-list"] {
    display: grid;
    gap: var(--mrg-semantic-space-stack-xs);
    padding: 0;
    margin: 0;
    list-style: none;
  }

  .mrg-file-manager [data-slot="file-manager-file-list"][data-view="grid"] {
    grid-template-columns: repeat(auto-fit, minmax(min(100%, 13rem), 1fr));
  }

  .mrg-file-manager [data-slot="file-manager-file-list"] button {
    display: flex;
    align-items: center;
    gap: var(--mrg-semantic-space-inline-sm);
    inline-size: 100%;
    min-block-size: var(--mrg-semantic-size-target-preferred);
    padding: var(--mrg-semantic-space-inset-sm);
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-default);
    border-radius: var(--mrg-semantic-radius-control);
    color: inherit;
    background: var(--mrg-semantic-color-background-canvas);
    font: inherit;
    text-align: start;
    cursor: pointer;
  }

  .mrg-file-manager [data-slot="file-manager-file-list"] button[aria-pressed="true"] {
    border-color: var(--mrg-semantic-color-selection-border);
    color: var(--mrg-semantic-color-selection-foreground);
    background: var(--mrg-semantic-color-selection-background);
  }

  .mrg-file-manager [data-slot="file-manager-file-mark"] {
    flex: none;
    min-inline-size: 2.5rem;
    padding: var(--mrg-semantic-space-inset-xs);
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-accent-border);
    border-radius: var(--mrg-semantic-radius-compact);
    color: var(--mrg-semantic-color-accent-foreground-on-subtle);
    background: var(--mrg-semantic-color-accent-background-subtle);
    font-family: var(--mrg-semantic-font-family-machine);
    font-size: var(--mrg-semantic-font-size-caption);
    text-align: center;
  }

  .mrg-file-manager [data-slot="file-manager-file-copy"] {
    display: grid;
    gap: var(--mrg-semantic-space-stack-xs);
    min-inline-size: 0;
  }

  .mrg-file-manager [data-slot="file-manager-file-copy"] strong {
    overflow-wrap: anywhere;
    font-weight: var(--mrg-semantic-font-weight-strong);
  }

  .mrg-file-manager [data-status="conflict"] {
    border-color: var(--mrg-semantic-color-status-warning-border);
  }

  .mrg-file-manager [data-slot="file-manager-preview-content"] dl,
  .mrg-file-manager [data-slot="file-manager-conflicts"] dl {
    display: grid;
    gap: var(--mrg-semantic-space-stack-sm);
    margin-block: var(--mrg-semantic-space-stack-md);
  }

  .mrg-file-manager dl div {
    display: grid;
    grid-template-columns: minmax(5rem, auto) minmax(0, 1fr);
    gap: var(--mrg-semantic-space-inline-sm);
  }

  .mrg-file-manager dt {
    color: var(--mrg-semantic-color-foreground-muted);
    font-size: var(--mrg-semantic-font-size-label);
    font-weight: var(--mrg-semantic-font-weight-label);
  }

  .mrg-file-manager dd {
    margin: 0;
    overflow-wrap: anywhere;
  }

  .mrg-file-manager form {
    display: grid;
    gap: var(--mrg-semantic-space-stack-xs);
    margin-block-start: var(--mrg-semantic-space-stack-md);
  }

  .mrg-file-manager :is(input, select) {
    min-block-size: var(--mrg-semantic-density-control-height);
    padding: var(--mrg-semantic-density-control-padding-block)
      var(--mrg-semantic-density-control-padding-inline);
    border: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-interactive);
    border-radius: var(--mrg-semantic-radius-control);
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-canvas);
    font: inherit;
  }

  .mrg-file-manager [data-slot="file-manager-offline"],
  .mrg-file-manager [data-slot="file-manager-error"],
  .mrg-file-manager [data-slot="file-manager-recovery"] {
    grid-column: 1 / -1;
    display: flex;
    align-items: center;
