    .mrg-file-manager [data-slot="file-manager-folders"] {
      border-inline-end: 0;
      border-block-end: var(--mrg-semantic-border-width-default) solid
        var(--mrg-semantic-color-border-default);
    }

    .mrg-file-manager [data-slot="file-manager-content"] {
      grid-template-columns: minmax(0, 1fr);
