  @media (prefers-reduced-motion: reduce) {
    .mrg-file-manager *,
    .mrg-file-manager *::before,
    .mrg-file-manager *::after {
      scroll-behavior: auto;
      transition-duration: var(--mrg-semantic-motion-duration-reduced);
      animation-duration: var(--mrg-semantic-motion-duration-reduced);
    }
  }

  @media (forced-colors: active) {
    .mrg-file-manager,
    .mrg-file-manager [data-slot="file-manager-file-list"] button,
    .mrg-file-manager :is(input, select) {
      border-color: CanvasText;
      color: CanvasText;
      background: Canvas;
      forced-color-adjust: auto;
    }

    .mrg-file-manager [data-slot="file-manager-file-list"] button[aria-pressed="true"] {
      border-color: Highlight;
      color: HighlightText;
      background: Highlight;
    }
  }
